function getPageNumbers(e,n){if(n<=7)return Array.from({length:n},(e,n)=>n+1);const a=[1];e>3&&a.push("...");for(let t=Math.max(2,e-1);t<=Math.min(n-1,e+1);t++)a.push(t);return e<n-2&&a.push("..."),n>1&&a.push(n),a}function renderPagination(e,n,a){const t=document.getElementById(e);if(!t)return;const{page:s,pages:o,total:i}=n;if(o<=1)return void(t.innerHTML="");let l='<div class="pagination">';l+=`<button class="page-btn" ${1===s?"disabled":""} \n             onclick="${a}(${s-1})" \n             aria-label="Previous page">\n             <i class="bi bi-chevron-left"></i>\n             </button>`;getPageNumbers(s,o).forEach(e=>{l+="..."===e?'<span class="page-ellipsis">...</span>':`<button class="page-btn ${e===s?"active":""}" \n                     onclick="${a}(${e})"\n                     aria-label="Page ${e}"\n                     ${e===s?'aria-current="page"':""}>${e}</button>`}),l+=`<button class="page-btn" ${s===o?"disabled":""} \n             onclick="${a}(${s+1})"\n             aria-label="Next page">\n             <i class="bi bi-chevron-right"></i>\n             </button>`,l+=`<span class="page-info">Page ${s} of ${o} (${i} total)</span>`,l+="</div>",t.innerHTML=l}function toggleExpandableRow(e){const n=document.getElementById(`details-${e}`),a=document.querySelector(`[data-expand="${e}"] .expand-icon`);if(!n||!a)return;"none"!==n.style.display?(n.style.display="none",a.classList.remove("expanded"),a.classList.remove("bi-chevron-up"),a.classList.add("bi-chevron-down")):(n.style.display="table-row",a.classList.add("expanded"),a.classList.remove("bi-chevron-down"),a.classList.add("bi-chevron-up"))}function collapseAllRows(){document.querySelectorAll(".details-row").forEach(e=>{e.style.display="none"}),document.querySelectorAll(".expand-icon").forEach(e=>{e.classList.remove("expanded","bi-chevron-up"),e.classList.add("bi-chevron-down")})}